// ================= DATA PRODUK =================
  const products = [
    {id:'kemeja',        name:'Baju Kemeja',          category:'Atasan',  price:150000},
    {id:'jeans-cewek',   name:'Celana Jeans Cewek',   category:'Bawahan', price:200000},
    {id:'kaos-polos',    name:'Kaos Polos Cowok',     category:'Atasan',  price:113000},
    {id:'dress',         name:'Dress',                category:'Dress',   price:230000},
    {id:'cardigan',      name:'Cardigan',             category:'Atasan',  price:50000},
    {id:'crop-top',      name:'Crop Top',             category:'Atasan',  price:67000},
    {id:'hoodie',        name:'Hoodie',               category:'Atasan',  price:80000},
    {id:'celana-pendek', name:'Celana Pendek',        category:'Bawahan', price:50000},
    {id:'kulot',         name:'Kulot',                category:'Bawahan', price:100000},
    {id:'celana-cargo',  name:'Celana Cargo',         category:'Bawahan', price:215000}
  ];

  let cart = {};
  let selectedPayment = null;
  const QRIS_IMAGE = "data:image/jpeg;base64,"; // Poster QRIS asli Ardill Fashion (ditanam permanen)

  function rupiah(n){ return 'Rp ' + n.toLocaleString('id-ID'); }
  function getProduct(id){ return products.find(p => p.id === id); }
  function getCardImg(id){
    const img = document.querySelector('#card-' + id + ' img');
    return img ? img.src : '';
  }

  // ================= CART =================
  function addToCart(id){
    cart[id] = (cart[id] || 0) + 1;
    renderCart();
    renderOrderProducts();
    pulseCart();
  }
  function changeCartQty(id, delta){
    if(!cart[id]) return;
    cart[id] += delta;
    if(cart[id] <= 0) delete cart[id];
    renderCart();
    renderOrderProducts();
  }
  function removeCartItem(id){
    delete cart[id];
    renderCart();
    renderOrderProducts();
  }
  function resetCart(){
    if(Object.keys(cart).length === 0) return;
    if(confirm('Kosongkan semua produk dari keranjang?')){
      cart = {};
      renderCart();
      renderOrderProducts();
    }
  }
  function cartTotal(){
    return Object.entries(cart).reduce((sum,[id,qty]) => sum + getProduct(id).price * qty, 0);
  }
  function cartCount(){
    return Object.values(cart).reduce((a,b) => a + b, 0);
  }
  function renderCart(){
    const badge = document.getElementById('cart-badge');
    const count = cartCount();
    badge.textContent = count;
    badge.style.display = count > 0 ? 'flex' : 'none';

    const list = document.getElementById('cart-items');
    const empty = document.getElementById('cart-empty');
    const ids = Object.keys(cart);
    list.innerHTML = '';
    if(ids.length === 0){
      empty.style.display = 'block';
    } else {
      empty.style.display = 'none';
      ids.forEach(id => {
        const p = getProduct(id);
        const qty = cart[id];
        const row = document.createElement('div');
        row.className = 'cart-row';
        row.innerHTML =
          '<img src="' + getCardImg(id) + '" alt="' + p.name + '">' +
          '<div class="cart-row-info">' +
            '<p class="cart-row-name">' + p.name + '</p>' +
            '<p class="cart-row-price">' + rupiah(p.price) + '</p>' +
            '<div class="qty-control">' +
              '<button onclick="changeCartQty(\'' + id + '\',-1)" aria-label="Kurangi">−</button>' +
              '<span>' + qty + '</span>' +
              '<button onclick="changeCartQty(\'' + id + '\',1)" aria-label="Tambah">+</button>' +
            '</div>' +
          '</div>' +
          '<button class="cart-row-remove" onclick="removeCartItem(\'' + id + '\')" aria-label="Hapus">✕</button>';
        list.appendChild(row);
      });
    }
    document.getElementById('cart-total').textContent = rupiah(cartTotal());
  }
  function toggleCartPanel(){
    document.getElementById('cart-panel').classList.toggle('open');
    document.getElementById('overlay').classList.toggle('show');
  }
  function closeCartPanel(){
    document.getElementById('cart-panel').classList.remove('open');
    document.getElementById('overlay').classList.remove('show');
  }
  function goToOrderForm(){
    closeCartPanel();
    document.getElementById('pesan').scrollIntoView({behavior:'smooth'});
  }
  function pulseCart(){
    const icon = document.getElementById('cart-icon-btn');
    icon.classList.add('pulse');
    setTimeout(() => icon.classList.remove('pulse'), 400);
  }

  // ================= FORM PESANAN =================
  function renderOrderProducts(){
    const wrap = document.getElementById('order-products');
    const ids = Object.keys(cart);
    if(ids.length === 0){
      wrap.innerHTML = '<p class="order-empty">Keranjang masih kosong. <a onclick="scrollToSection(\'katalog\')" style="cursor:pointer;">Pilih produk di katalog</a> lalu klik “+ Keranjang”.</p>';
      updateOrderTotal();
      return;
    }
    wrap.innerHTML = ids.map(id => {
      const p = getProduct(id);
      const qty = cart[id];
      return (
        '<label class="order-product-row">' +
          '<input type="checkbox" class="order-check" data-id="' + id + '" checked onchange="updateOrderTotal()">' +
          '<img src="' + getCardImg(id) + '" alt="' + p.name + '">' +
          '<span class="order-product-name">' + p.name + '</span>' +
          '<span class="order-qty-control">' +
            '<button type="button" onclick="event.preventDefault();changeCartQty(\'' + id + '\',-1)">−</button>' +
            '<span>' + qty + '</span>' +
            '<button type="button" onclick="event.preventDefault();changeCartQty(\'' + id + '\',1)">+</button>' +
          '</span>' +
          '<span class="order-product-price">' + rupiah(p.price * qty) + '</span>' +
        '</label>'
      );
    }).join('');
    updateOrderTotal();
  }
  function updateOrderTotal(){
    const checks = document.querySelectorAll('.order-check');
    let total = 0;
    checks.forEach(c => {
      if(c.checked && cart[c.dataset.id]){
        total += getProduct(c.dataset.id).price * cart[c.dataset.id];
      }
    });
    document.getElementById('order-total').textContent = rupiah(total);
    return total;
  }

  function selectPayment(method, el){
    selectedPayment = method;
    document.querySelectorAll('.payment-option').forEach(o => o.classList.remove('active'));
    el.classList.add('active');
  }

  function lanjutPembayaran(){
    const nama = document.getElementById('inp-nama').value.trim();
    const alamatKota = document.getElementById('inp-alamat-singkat').value.trim();
    const alamatLengkap = document.getElementById('inp-alamat').value.trim();
    const alamat = (alamatLengkap + (alamatKota ? ', ' + alamatKota : '')).trim();
    const ig = document.getElementById('inp-ig').value.trim();
    const hp = document.getElementById('inp-hp').value.trim();
    const checks = document.querySelectorAll('.order-check:checked');

    if(!nama || !alamatLengkap || !ig || !hp){
      alert('Mohon lengkapi nama, alamat lengkap, username Instagram, dan no. HP terlebih dahulu.');
      return;
    }
    if(checks.length === 0){
      alert('Pilih minimal satu produk pesanan (tambahkan dari katalog ke keranjang).');
      return;
    }
    if(!selectedPayment){
      alert('Pilih metode pembayaran terlebih dahulu.');
      return;
    }

    const total = updateOrderTotal();
    const items = Array.from(checks).map(c => {
      const p = getProduct(c.dataset.id);
      return p.name + ' x' + cart[c.dataset.id];
    });

    showPaymentModal({nama, alamat, ig, hp, items, total});
  }

  function showPaymentModal(data){
    const nama = data.nama, alamat = data.alamat, ig = data.ig, hp = data.hp, items = data.items, total = data.total;
    const modal = document.getElementById('payment-modal');
    const body = document.getElementById('payment-modal-body');
    const igClean = ig.replace('@','');
    let methodHtml = '';

    if(selectedPayment === 'cash'){
      methodHtml =
        '<div class="pm-icon">💵</div>' +
        '<h4>Pembayaran Tunai (Cash)</h4>' +
        '<p>Silakan siapkan uang tunai sebesar berikut saat barang diambil/diterima:</p>' +
        '<p class="pm-total">' + rupiah(total) + '</p>' +
        '<p class="pm-address">Jln. Pasirluyu IV No. 13, Ancol, Kec. Regol, Kota Bandung</p>';
    } else if(selectedPayment === 'qris'){
      methodHtml =
        '<h4>Pembayaran QRIS</h4>' +
        '<img class="qr-image" src="' + QRIS_IMAGE + '" alt="QR Code QRIS Ardill Fashion, Regol">' +
        '<p>Scan QR di atas dari aplikasi e-wallet atau m-banking apa saja, lalu bayar sebesar:</p>' +
        '<p class="pm-total">' + rupiah(total) + '</p>';
    } else if(selectedPayment === 'dana'){
      methodHtml =
        '<div class="pm-icon">💳</div>' +
        '<h4>E-Wallet DANA</h4>' +
        '<p>Transfer ke nomor DANA berikut:</p>' +
        '<p class="pm-rekening">082216889411</p>' +
        '<p>a.n. Ardill Fashion, sejumlah:</p>' +
        '<p class="pm-total">' + rupiah(total) + '</p>';
    }

    const waMessage = encodeURIComponent(
      'Halo Ardill Fashion, saya ingin konfirmasi pesanan:\n' +
      'Nama: ' + nama + '\n' +
      'Alamat: ' + alamat + '\n' +
      'Instagram: @' + igClean + '\n' +
      'No HP: ' + hp + '\n' +
      'Produk: ' + items.join(', ') + '\n' +
      'Total: ' + rupiah(total) + '\n' +
      'Metode Bayar: ' + selectedPayment.toUpperCase()
    );

    body.innerHTML =
      methodHtml +
      '<hr style="border:none;border-top:1px solid var(--border-soft);margin:18px 0;">' +
      '<div class="pm-summary">' +
        '<p><strong>Ringkasan Pesanan</strong></p>' +
        '<p>Nama: ' + nama + '</p>' +
        '<p>Alamat: ' + alamat + '</p>' +
        '<p>Instagram: @' + igClean + '</p>' +
        '<p>No. HP: ' + hp + '</p>' +
        '<p>Produk: ' + items.join(', ') + '</p>' +
        '<p>Total: <strong>' + rupiah(total) + '</strong></p>' +
      '</div>' +
      '<a class="btn-wa-confirm" target="_blank" rel="noopener" href="https://wa.me/6282216889411?text=' + waMessage + '">Konfirmasi via WhatsApp</a>';

    modal.classList.add('show');
  }
  function closePaymentModal(){
    document.getElementById('payment-modal').classList.remove('show');
  }

  // ================= SEARCH =================
  const searchInput = document.getElementById('search-input');
  const suggestionsBox = document.getElementById('search-suggestions');
  searchInput.addEventListener('input', () => {
    const q = searchInput.value.trim().toLowerCase();
    if(!q){ suggestionsBox.classList.remove('show'); suggestionsBox.innerHTML=''; return; }
    const matches = products.filter(p => p.name.toLowerCase().includes(q)).slice(0,6);
    if(matches.length === 0){
      suggestionsBox.innerHTML = '<div class="suggestion-empty">Produk tidak ditemukan</div>';
    } else {
      suggestionsBox.innerHTML = matches.map(p =>
        '<div class="suggestion-item" onclick="goToProduct(\'' + p.id + '\')">' +
          '<img src="' + getCardImg(p.id) + '" alt="' + p.name + '">' +
          '<span>' + p.name + '</span>' +
          '<span class="suggestion-price">' + rupiah(p.price) + '</span>' +
        '</div>'
      ).join('');
    }
    suggestionsBox.classList.add('show');
  });
  document.addEventListener('click', (e) => {
    if(!e.target.closest('.search-wrap')) suggestionsBox.classList.remove('show');
  });
  function goToProduct(id){
    suggestionsBox.classList.remove('show');
    searchInput.value = '';
    const card = document.getElementById('card-' + id);
    if(card){
      card.scrollIntoView({behavior:'smooth', block:'center'});
      card.classList.add('highlight');
      setTimeout(() => card.classList.remove('highlight'), 1600);
    }
  }

  // ================= HERO CAROUSEL =================
  let heroIndex = 0;
  function showHeroSlide(i){
    heroIndex = (i + 3) % 3;
    document.getElementById('hero-track').style.transform = 'translateX(-' + (heroIndex * 33.3333) + '%)';
  }
  function heroPrev(){ showHeroSlide(heroIndex - 1); }
  function heroNext(){ showHeroSlide(heroIndex + 1); }

  // ================= MOBILE SIDEBAR =================
  function toggleSidebar(){
    document.getElementById('sidebar').classList.toggle('open');
    document.getElementById('overlay').classList.toggle('show');
  }
  document.getElementById('overlay').addEventListener('click', () => {
    document.getElementById('sidebar').classList.remove('open');
    document.getElementById('cart-panel').classList.remove('open');
    document.getElementById('overlay').classList.remove('show');
  });

  // ================= NAVIGASI INTERNAL (tanpa link/href) =================
  // Dipakai oleh logo, menu sidebar, tombol "Lihat Katalog", dan link
  // "Pilih produk di katalog" — semua murni lewat JavaScript, tidak
  // menampilkan URL/anchor apa pun, langsung scroll ke section tujuan.
  function scrollToSection(id){
    const el = document.getElementById(id);
    if(el){
      el.scrollIntoView({behavior:'smooth'});
    }
    document.getElementById('sidebar').classList.remove('open');
    document.getElementById('overlay').classList.remove('show');
  }

  // ================= INIT =================
  renderCart();
  renderOrderProducts();